    """Yield tuples whose elements are offset from *iterable*

>>> list(offset_views([0, 1, 2, 3]))
[(None, 0, 1), (0, 1, 2), (1, 2, 3)]
>>> list(offset_views(range(8), offsets=(0, 2, 4)))
[(0, 2, 4), (1, 3, 5), (2, 4, 6), (3, 5, 7)]"""
    from itertools import islice, tee, zip_longest, chain

    iterables = tee(iterable, len(offsets))
    staggered = []

    for it, offset in zip(iterables, offsets):
        if offset < 0:
            padded = chain([fillvalue] * (-offset), it)
        else:
            padded = islice(it, offset, None)
        staggered.append(padded)

    if longest:
        return zip_longest(*staggered, fillvalue=fillvalue)
    else:
