def min_and_max(iterable_or_value, *others, key=None, default=_marker):
    """Returns both the smallest and largest items from an iterable
or from two or more arguments

>>> min_and_max([3, 1, 5])
(1, 5)
>>> min_and_max(4, 2, 6)
(2, 6)"""
    if others:
        iterable = (iterable_or_value,) + others
    else:
        iterable = iterable_or_value

    iterator = iter(iterable)

    try:
        min_val = max_val = next(iterator)
    except StopIteration:
        if default is _marker:
            raise ValueError('min_and_max() argument is an empty sequence')
        return (default, default)

    if key is None:
        for item in iterator:
            if item < min_val:
                min_val = item
            if item > max_val:
                max_val = item
    else:
        min_key = max_key = key(min_val)
        for item in iterator:
            item_key = key(item)
            if item_key < min_key:
                min_val = item
                min_key = item_key
            if item_key > max_key:
                max_val = item
                max_key = item_key

    return (min_val, max_val)

